set define off;

  CREATE OR REPLACE PROCEDURE "EZEKP2017"."APRAPPROVEEND" /****** 개체: 저장 프로시저 dbo.APRApproveEnd    스크립트 날짜: 2004-05-11 오전 11:54:15 ******/
/****** 개체: 저장 프로시저 dbo.APRApproveEnd    스크립트 날짜: 2004-01-26 오후 3:57:27 ******/
(
  v_DocID IN CHAR,
  v_endURL IN VARCHAR2,
  v_ContainerID IN CHAR
)
AS
   v_sys_error NUMBER := 0;
   v_sys_errText VARCHAR2(1000) := '';
BEGIN

   INSERT INTO TBL_ENDAPRDOCINFO
     ( DocID, FormID, OrgDocID, DocType, DocState, FunctionType, Href, DocTitle, DocNo, HasAttachYN, HasOpinionYN, StartDate, WriterID, EndDate, WriterName, WriterName2, WriterJobTitle, WriterJobTitle2, WriterDeptID, WriterDeptName, WriterDeptName2, ContainerID, isPublic )
     ( SELECT v_DocID ,
              FormID ,
              OrgDocID ,
              DocType ,
              DocState ,
              '003' ,
              v_endURL ,
              DocTitle ,
              DocNo ,
              HasAttachYN ,
              HasOpinionYN ,
              StartDate ,
              WriterID ,
              SYSDATE ,
              WriterName ,
              WriterName2 ,
              WriterJobTitle ,
              WriterJobTitle2 ,
              WriterDeptID ,
              WriterDeptName ,
              WriterDeptName2 ,
              v_ContainerID ,
              isPublic 
       FROM TBL_APRDOCINFO 
        WHERE  DocID = v_DocID );
   INSERT INTO TBL_ENDAPRLINEINFO
     ( DocID, AprMemberSN, AprType, AprState, AprMemberID, AprMemberIsDeptYN, AprMemberName, AprMemberName2, AprMemberJobTitle, AprMemberJobTitle2, AprMemberDeptID, AprMemberDeptName, AprMemberDeptName2, AprMemberLDAPPath, ReceivedDate, ReasonDoNotApproval, ProcessDate, isProposerYN, isBriefUserYN )
     ( SELECT v_DocID ,
              AprMemberSN ,
              AprType ,
              AprState ,
              AprMemberID ,
              AprMemberIsDeptYN ,
              AprMemberName ,
              AprMemberName2 ,
              AprMemberJobTitle ,
              AprMemberJobTitle2 ,
              AprMemberDeptID ,
              AprMemberDeptName ,
              AprMemberDeptName2 ,
              AprMemberLDAPPath ,
              ReceivedDate ,
              ReasonDoNotApprov ,
              ProcessDate ,
              isProposerYN ,
              isBriefUserYN 
       FROM TBL_APRLINEINFO 
        WHERE  DOCID = v_DocID );
   INSERT INTO TBL_ENDATTACHINFO
     ( DocID, AttachFileSN, AttachFileName, AttachFileHref, AttachUserJobTitle, AttachUserJobTitle2, AttachFileSize, AttachUserID, AttachUserName, AttachUserName2, AttachUserDeptID, AttachUserDeptName, AttachUserDeptName2, PageNum, DisplayName, BodyAttach )
     ( SELECT v_DocID ,
              AttachFileSN ,
              AttachFileName ,
              AttachFileHref ,
              AttachUserJobTitle ,
              AttachUserJobTitle2 ,
              AttachFileSize ,
              AttachUserID ,
              AttachUserName ,
              AttachUserName2 ,
              AttachUserDeptID ,
              AttachUserDeptName ,
              AttachUserDeptName2 ,
              PageNum ,
              DisplayName ,
              BodyAttach 
       FROM TBL_APRATTACHINFO 
        WHERE  DOCID = v_DocID );
   INSERT INTO TBL_ENDAPRDOCATTACHINFO
     ( DocID, AttachSN, AttachDocName, AttachDocURL, SubAttachYN, AttachUserID, AttachUserName, AttachUserName2, AttachUserDeptID, AttachUserDeptName, AttachUserDeptName2, AttachUserJobTitle, AttachUserJobTitle2 )
     ( SELECT v_DocID ,
              AttachSN ,
              AttachDocName ,
              AttachDocURL ,
              SubAttachYN ,
              AttachUserID ,
              AttachUserName ,
              AttachUserName2 ,
              AttachUserDeptID ,
              AttachUserDeptName ,
              AttachUserDeptName2 ,
              AttachUserJobTitle ,
              AttachUserJobTitle2 
       FROM TBL_APRDOCATTACHINFO 
        WHERE  DOCID = v_DocID );
   INSERT INTO TBL_ENDAPROPINIONINFO
     ( DocID, UserID, OpinionGB, CONTENT, UserName, UserName2, UserJobTitle, UserJobTitle2, UserDeptID, UserDeptName, UserDeptName2, OpinionSN )
     ( SELECT v_DocID ,
              UserID ,
              OpinionGB ,
              CONTENT ,
              UserName ,
              UserName2 ,
              UserJobTitle ,
              UserJobTitle2 ,
              UserDeptID ,
              UserDeptName ,
              UserDeptName2 ,
              OpinionSN 
