/
--------------------------------------------------------
--  DDL for Function FGETCABTRANSSTATUS
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."FGETCABTRANSSTATUS" /****** 개체:  사용자 정의 함수 dbo.fGetCabTransStatus    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
(
  iv_StatusCode IN NUMBER,
  v_LANGTYPE IN NUMBER
)
RETURN VARCHAR2
AS
   v_StatusCode NUMBER := iv_StatusCode;
   v_rtnStr VARCHAR2(50);
/******기록물철의 이관/생산현황 보고 상태를 return******/
/*
@StatusCode: 생산현황보고의 경우-ProdReportFlag, 이관의 경우-TransferFlag
*/

BEGIN
   /*
   ######## @Status  ########
   0: 목록미전송[생산/이관]
   1: 목록전송오류(파일미전송)[생산/이관]
   2: 목록전송완료(파일미전송)[생산/이관]
   4: 파일전송중오류[이관]
   8: 파일전송 중[이관]
   16: 파일전송완료[이관]
   32: 이관접수오류[이관]
   64: 이관접수완료[이관]
   128: 반려[생산/이관]
   256: 인수완료[생산/이관]
   */
   IF ( v_LANGTYPE = 1 ) THEN

   BEGIN
      IF ( v_StatusCode IS NULL ) THEN
       v_StatusCode := 0 ;
      END IF;
      --인수완료/반려여부
      IF ( v_StatusCode = 256 ) THEN
       v_rtnStr := '인수완료' ;
      ELSE
         IF (v_StatusCode = 64 ) THEN
          v_rtnStr := '접수완료' ;
         ELSE
            IF ( v_StatusCode = 16 ) THEN
             v_rtnStr := '파일전송완료' ;
            ELSE
               IF ( v_StatusCode = 2 ) THEN
                v_rtnStr := '목록전송완료' ;
               ELSE
                  IF ( v_StatusCode = 128 ) THEN
                   v_rtnStr := '반려' ;
                  ELSE
                     v_rtnStr := '미전송' ;
                  END IF;
               END IF;
            END IF;
         END IF;
      END IF;

   END;
   ELSE

   BEGIN
      IF ( v_StatusCode IS NULL ) THEN
       v_StatusCode := 0 ;
      END IF;
      --인수완료/반려여부
      IF ( v_StatusCode=256 ) THEN
       v_rtnStr := 'TAKEOVERS COMPLETION' ;
      ELSE
         IF ( v_StatusCode = 64 ) THEN
          v_rtnStr := 'RECEIPT COMPLETION' ;
         ELSE
            IF ( v_StatusCode = 16 ) THEN
             v_rtnStr := 'FILE TRANSFER COMPLETION' ;
            ELSE
               IF ( v_StatusCode = 2 ) THEN
                v_rtnStr := 'LIST TRANSMISSION COMPLETION' ;
               ELSE
                  IF (v_StatusCode = 128 ) THEN
                   v_rtnStr := 'RETURN' ;
                  ELSE
                     v_rtnStr := 'NOT TRANSFER' ;
                  END IF;
               END IF;
            END IF;
         END IF;
      END IF;

   END;
   END IF;
   RETURN v_rtnStr;

--EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function FGETDEPTTRANSSTATUS
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."FGETDEPTTRANSSTATUS" /****** 개체:  사용자 정의 함수 dbo.fGetDeptTransStatus    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
(
  iv_StatusCode IN CHAR,
  v_langType IN CHAR
)
RETURN VARCHAR2
AS
   v_StatusCode CHAR(7) := iv_StatusCode;
   v_ListTransStatus --목록전송 상태
    VARCHAR2(50);
   v_FileTransStatus --파일전송 상태
    VARCHAR2(50);
   v_ReceiveStatus --자료관접수 상태
    VARCHAR2(50);
   v_RcvCmplStatus VARCHAR2(50);--인수완료/반려 여부
/******각 처리과별로 이관/생산현황보고 시 상태를 return******/
/*
각 단계별 상태를 ':'를 구분자로 하는 연결된 스트링으로 리턴한다.
*/

BEGIN
   /*
   ######## @Status  ########
   0: 목록미전송[생산/이관]
   1: 목록전송오류(파일미전송)[생산/이관]
   2: 목록전송완료(파일미전송)[생산/이관]
   4: 파일전송중오류[이관]
   8: 파일전송 중[이관]
   16: 파일전송완료[이관]
   32: 이관접수오류[이관]
   64: 이관접수완료[이관]
   128: 반려[생산/이관]
   256: 인수완료[생산/이관]
   ######## @결과리턴 형식 #####
   목록전송상태[생/이]           파일전송상태[이]                             자료관접수상태[이]            인수완료/반려 여부[생/이]
   ----------------------------------------------------------------------------------------------------------------
   미전송/전송완료/전송오류   미전송/전송중/전송중오류/전송완료   미접수/접수완료/접수오류   완료/미완료/반려
   */
   IF ( v_langType = '1' ) THEN

   BEGIN
      IF ( v_StatusCode IS NULL ) THEN
       v_StatusCode := 0 ;
      END IF;
      --인수완료/반려여부
      IF ( UTILS.BIT_AND(v_StatusCode,256) = 256 ) THEN
       v_RcvCmplStatus := '완료' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,128) = 128 ) THEN
          v_RcvCmplStatus := '반려' ;
         ELSE
            v_RcvCmplStatus := '미완료' ;
         END IF;
      END IF;
      --자료관 접수상태
      IF ( UTILS.BIT_AND(v_StatusCode,64) = 64 ) THEN
       v_ReceiveStatus := '접수완료' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,32) = 32 ) THEN
          v_ReceiveStatus := '접수오류' ;
         ELSE
            v_ReceiveStatus := '미접수' ;
         END IF;
      END IF;
      --파일전송 상태
      IF ( UTILS.BIT_AND(v_StatusCode,16) = 16 ) THEN
       v_FileTransStatus := '파일전송완료' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,8) = 8 ) THEN
          v_FileTransStatus := '파일전송중' ;
         ELSE
            IF ( UTILS.BIT_AND(v_StatusCode,4) = 4 ) THEN
             v_FileTransStatus := '파일전송중오류' ;
            ELSE
               v_FileTransStatus := '미전송' ;
            END IF;
         END IF;
      END IF;
      --목록전송 상태
      IF ( UTILS.BIT_AND(v_StatusCode,2) = 2 ) THEN
       v_ListTransStatus := '목록전송완료' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,1) = 1 ) THEN
          v_ListTransStatus := '목록전송오류' ;
         ELSE
            v_ListTransStatus := '미전송' ;
         END IF;
      END IF;

   END;
   ELSE

   BEGIN
      IF ( v_StatusCode IS NULL ) THEN
       v_StatusCode := 0 ;
      END IF;
      --인수완료/반려여부
      IF ( UTILS.BIT_AND(v_StatusCode,256) = 256 ) THEN
       v_RcvCmplStatus := 'complete' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,128) = 128 ) THEN
          v_RcvCmplStatus := 'RETURN' ;
         ELSE
            v_RcvCmplStatus := 'INCOMPLETE' ;
         END IF;
      END IF;
      --자료관 접수상태
      IF ( UTILS.BIT_AND(v_StatusCode,64) = 64 ) THEN
       v_ReceiveStatus := 'RECEIPT COMPLETION' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,32) = 32 ) THEN
          v_ReceiveStatus := 'RECEIPT ERROR' ;
         ELSE
            v_ReceiveStatus := 'NOT RECEIVE' ;
         END IF;
      END IF;
      --파일전송 상태
      IF ( UTILS.BIT_AND(v_StatusCode,16) = 16 ) THEN
       v_FileTransStatus := 'FILE TRANSFER COMPLETION' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,8) = 8 ) THEN
          v_FileTransStatus := 'FILE TRANSFERRING' ;
         ELSE
            IF ( UTILS.BIT_AND(v_StatusCode,4) = 4 ) THEN
             v_FileTransStatus := 'FILE TRANSFER ERROR' ;
            ELSE
               v_FileTransStatus := 'NOT TRANSFER' ;
            END IF;
         END IF;
      END IF;
      --목록전송 상태
      IF ( UTILS.BIT_AND(v_StatusCode,2) = 2 ) THEN
       v_ListTransStatus := 'LIST TRANSMISSION COMPLETION' ;
      ELSE
         IF ( UTILS.BIT_AND(v_StatusCode,1) = 1 ) THEN
          v_ListTransStatus := 'LIST TRANSMISSION ERROR' ;
         ELSE
            v_ListTransStatus := 'NOT TRANSFER' ;
         END IF;
      END IF;

   END;
   END IF;
   RETURN v_ListTransStatus || ':' || v_FileTransStatus || ':' || v_ReceiveStatus || ':' || v_RcvCmplStatus;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function FGETTBLLISTTRANSTARGET
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."FGETTBLLISTTRANSTARGET" /****** 개체:  사용자 정의 함수 dbo.fGetTblListTransTarget    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
(
  v_DeptCode IN CHAR,
  v_TransYear IN NUMBER
)
RETURN ezApprovalG_S907000.fGetTb_pkg.tt_fGetTblListTransTarget_type PIPELINED
AS
   v_temp SYS_REFCURSOR;
   v_temp_1 TT_FGETTBLLISTTRANSTARGET%ROWTYPE;

BEGIN
   /* 목록이관 대상 목록을 리턴한다.*/
   DELETE tt_fGetTblListTransTarget;

   INSERT INTO tt_fGetTblListTransTarget
      SELECT TBCABINET.CabinetID ,
             TBCABINET.CabinetClassNo ,
             TBCABCLASS.ProcessDeptCode ,
             TBCABCLASS.ProductionYear ,
             TBCABCLASS.TaskCode ,
             TBCABCLASS.RegSerialNo ,
             TBCABINET.VolumeNo ,
             TBCABCLASS.Title ,
             TBCABCLASS.RecTypeCode ,
             TBCABCLASS.ExpirationYear ,
             TBCABCLASS.KeepingPeriod ,
             TBCABCLASS.KeepingMethod ,
             TBCABCLASS.KeepingPlace ,
             TBCABCLASS.DisplayRecFlag ,
             TBCABCLASS.DisplayEndDate ,
             TBCABCLASS.DisplayReason ,
             TBCABCLASS.OldCabinetFlag ,
             TBCABCLASS.ModifyFlag ,
             TBCABINET.CabinetTransferFlag ,
             TBCABINET.TDeptCode ,
             TBCABINET.TTaskCode ,
             TBCABINET.TProduceYear ,
             TBCABINET.TRegSerialNo ,
             TBCABINET.TVolumeNo ,
             TransferFlag ,
             TBCABINET.CreateDate ,
             OwnerDeptID ,
             ConfirmYear 
        FROM TBCABINETCLASS TBCABCLASS
               JOIN TBCABINET    ON TBCABCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
       WHERE  TBCABCLASS.DelFlag = '0'
                AND OwnerDeptID = v_DeptCode
                AND ConfirmFlag = '1'
                AND ( ( DisplayRecFlag = '2'
                AND ConfirmYear BETWEEN (v_TransYear - 1) AND v_TransYear
                AND TransDelayFlag = '0' )
                OR ( DisplayRecFlag = '1'
                AND DisplayEndDate < UTILS.CONVERT_TO_CHAR(v_TransYear,4)
                OR ( TransDelayFlag = '1'
                AND ExTransYear = v_TransYear ) ) )
                AND TBCABINET.DelFlag = '0'
                AND NOT ( TBCABINET.CabinetTransferFlag = '2' );

      OPEN v_temp FOR
      SELECT * 
        FROM tt_fGetTblListTransTarget;

   LOOP
      FETCH v_temp INTO v_temp_1;
      EXIT WHEN v_temp%NOTFOUND;
      PIPE ROW ( v_temp_1 );
   END LOOP;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function FN_STRINGTOTABLE
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."FN_STRINGTOTABLE" 
-- 수정(2006.01.03) : 영문 SQL이므로 COLLATE Korean_Wansung_CI_AS 구문 추가

(
  v_ArrayString IN CLOB,
  v_Delimiter IN VARCHAR2
)
RETURN ezApprovalG_S907000.fn_Str_pkg.tt_v_ArrayTable_type PIPELINED
AS
   v_iPosStart NUMBER(10,0);
   v_iPosEnd NUMBER(10,0);
   v_iLenDelim NUMBER(3,0);
   v_iExit NUMBER(3,0);
   v_vcStr VARCHAR2(100);
   v_temp SYS_REFCURSOR;
   v_temp_1 TT_V_ARRAYTABLE%ROWTYPE;

BEGIN
   v_iPosStart := 1 ;
   v_iPosEnd := 1 ;
   v_iLenDelim := LENGTH(v_Delimiter) ;
   v_iExit := 0 ;
   -- 모든 항목을 검색할 때까지 루트 처리
   WHILE v_iExit = 0 
   LOOP 

      BEGIN
         -- 구분문자를 기준으로 다음 항목의 위치 검색
         v_iPosEnd := INSTR(v_ArrayString, v_Delimiter, v_iPosStart) ;
         IF v_iPosEnd <= 0 THEN

         BEGIN
            v_iPosEnd := LENGTH(v_ArrayString) + 1 ;
            v_iExit := 1 ;

         END;
         END IF;
         v_vcStr := RTRIM(LTRIM(SUBSTR(v_ArrayString, v_iPosStart, v_iPosEnd - v_iPosStart))) ;
         -- 테이블 변수에 저장
         INSERT INTO tt_v_ArrayTable
           ( VALUE )
           VALUES ( v_vcStr );
         -- 다음 검색 위치로 이동
         v_iPosStart := v_iPosEnd + v_iLenDelim ;

      END;
   END LOOP;
   OPEN v_temp FOR
      SELECT * 
        FROM tt_v_ArrayTable;

   LOOP
      FETCH v_temp INTO v_temp_1;
      EXIT WHEN v_temp%NOTFOUND;
      PIPE ROW ( v_temp_1 );
   END LOOP;

--EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function FN_STRINGTOTABLE1
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."FN_STRINGTOTABLE1" 
-- 수정(2006.01.03) : 영문 SQL이므로 COLLATE Korean_Wansung_CI_AS 구문 추가

(
  v_ArrayString IN VARCHAR2,
  v_ArrayString1 IN VARCHAR2,
  v_ArrayString2 IN VARCHAR2,
  v_Delimiter IN VARCHAR2
)
RETURN fn_Str_pkg.tt_v_ArrayTable_type PIPELINED
AS
   v_iPosStart NUMBER(10,0);
   v_iPosEnd NUMBER(10,0);
   v_iLenDelim NUMBER(3,0);
   v_iExit NUMBER(3,0);
   v_iPosStart1 NUMBER(10,0);
   v_iPosEnd1 NUMBER(10,0);
   v_iLenDelim1 NUMBER(3,0);
   v_iPosStart2 NUMBER(10,0);
   v_iPosEnd2 NUMBER(10,0);
   v_iLenDelim2 NUMBER(3,0);
   v_vcStr VARCHAR2(100);
   v_vcStr1 VARCHAR2(100);
   v_vcStr2 VARCHAR2(100);
   v_temp SYS_REFCURSOR; 
   v_temp_1 tt_V_ARRAYTABLE%ROWTYPE;
--   PRAGMA AUTONOMOUS_TRANSACTION;
BEGIN
   v_iPosStart := 1 ;
   v_iPosEnd := 1 ;
   v_iLenDelim := LENGTH(v_Delimiter) ;
   v_iExit := 0 ;
   v_iPosStart1 := 1 ;
   v_iPosEnd1 := 1 ;
   v_iPosStart2 := 1 ;
   v_iPosEnd2 := 1 ;
   -- 모든 항목을 검색할 때까지 루트 처리

   WHILE v_iExit = 0 
   LOOP 

      BEGIN
         -- 구분문자를 기준으로 다음 항목의 위치 검색
         v_iPosEnd := INSTR(v_ArrayString, v_Delimiter, v_iPosStart) ;
         v_iPosEnd1 := INSTR(v_ArrayString1, v_Delimiter, v_iPosStart1) ;
         v_iPosEnd2 := INSTR(v_ArrayString2, v_Delimiter, v_iPosStart2) ;
         IF v_iPosEnd <= 0 THEN

         BEGIN
            v_iPosEnd := LENGTH(v_ArrayString) + 1 ;
            v_iExit := 1 ;

         END;
         END IF;
         IF v_iPosEnd1 <= 0 THEN

         BEGIN
            v_iPosEnd1 := LENGTH(v_ArrayString1) + 1 ;


         END;
         END IF;
         IF v_iPosEnd2 <= 0 THEN

         BEGIN
            v_iPosEnd2 := LENGTH(v_ArrayString2) + 1 ;


         END;
         END IF;
         v_vcStr := TRIM(SUBSTR(v_ArrayString, v_iPosStart, v_iPosEnd - v_iPosStart)) ;
         v_vcStr1 := TRIM(SUBSTR(v_ArrayString1, v_iPosStart1, v_iPosEnd1 - v_iPosStart1)) ;
         v_vcStr2 := TRIM(SUBSTR(v_ArrayString2, v_iPosStart2, v_iPosEnd2 - v_iPosStart2)) ;
         -- 테이블 변수에 저장

         INSERT INTO tt_v_ArrayTable
           ( VALUE,VALUE1,VALUE2 )
           VALUES ( v_vcStr,v_vcStr1,v_vcStr2 );

         -- 다음 검색 위치로 이동 
         v_iPosStart := v_iPosEnd + v_iLenDelim ;
         v_iPosStart1 := v_iPosEnd1 + v_iLenDelim ;
         v_iPosStart2 := v_iPosEnd2 + v_iLenDelim ;

      END; 
   END LOOP;
   OPEN v_temp FOR
      SELECT * 
        FROM tt_v_ArrayTable;

   LOOP
      FETCH v_temp INTO v_temp_1;
      EXIT WHEN v_temp%NOTFOUND;
      PIPE ROW (v_temp_1);

   END LOOP;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


