/
--------------------------------------------------------
--  DDL for Function GETCABPAGESTATBL
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."GETCABPAGESTATBL" /****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl    스크립트 날짜: 2004-01-26 오후 3:59:54 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl    스크립트 날짜: 2003-11-26 오후 3:39:10 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl    스크립트 날짜: 2003-10-27 오후 2:49:27 ******/
(
  v_DeptCode IN CHAR,
  v_sYear IN NUMBER,
  v_eYear IN NUMBER
)
RETURN ezApprovalG_S907000.GetCab_pkg.tt_GetCabPageStaTbl2_type PIPELINED
AS
   v_temp SYS_REFCURSOR;
   v_temp_1 TT_GETCABPAGESTATBL2%ROWTYPE;

BEGIN
   DELETE tt_GetCabPageStaTbl2;

   INSERT INTO tt_GetCabPageStaTbl2
      SELECT STB1.CabinetID ,
             REPLACE(utils.str(NumOfRec, 3), ' ', '0') NumOfRec  ,
             REPLACE(utils.str(PageOfRec, 6), ' ', '0') PageOfRec 
--             REPLACE(utils.str(NumOfElec, 6), ' ', '0') NumOfElec  
        FROM ( SELECT CabinetID ,
                      COUNT(*)  NumOfRec  ,
                      SUM(UTILS.CONVERT_TO_NUMBER(NumOfPage,19,0))  PageOfRec  
               FROM TBSEPERATEATTACH 
                WHERE  CabinetID IN ( SELECT CabinetID 
                                      FROM ( SELECT CabinetClassNo 
                                             FROM TBCABINETCLASS 
                                              WHERE  DelFlag = '0'
                                                       AND OwnerDeptID = v_DeptCode
                                                       AND ConfirmFlag = '1'
                                                       AND ConfirmYear BETWEEN v_sYear AND v_eYear ) TBCABINETCLASS
                                             JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo )

                         AND DelFlag = '0'
                 GROUP BY CabinetID ) STB1
               FULL JOIN ( SELECT CabinetID ,
                                  COUNT(RecKey)  NumOfElec  
                           FROM ( SELECT RecordID ,
                                         RecordID + SeperateAttachNo RecKey  ,
                                         CabinetID 
                                  FROM TBSEPERATEATTACH 
                                   WHERE  CabinetID IN ( SELECT CabinetID 
                                                         FROM ( SELECT CabinetClassNo 
                                                                FROM TBCABINETCLASS 
                                                                 WHERE  DelFlag = '0'
                                                                          AND OwnerDeptID = v_DeptCode
                                                                          AND ConfirmFlag = '1'
                                                                          AND ConfirmYear BETWEEN v_sYear AND v_eYear ) TBCABINETCLASS
        JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo )

                                            AND DelFlag = '0' ) TBSEPERATEATTACH
                                  JOIN TBRECORD    ON TBSEPERATEATTACH.RecordID = TBRECORD.RecordID
                            WHERE  DocID IS NOT NULL
                             GROUP BY CabinetID ) STB2   ON STB1.CabinetID = STB2.CabinetID;

      OPEN v_temp FOR
      SELECT * 
        FROM tt_GetCabPageStaTbl2;

   LOOP
      FETCH v_temp INTO v_temp_1;
      EXIT WHEN v_temp%NOTFOUND;
      PIPE ROW ( v_temp_1 );
   END LOOP;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function GETCABPAGESTATBL2
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."GETCABPAGESTATBL2" /****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl2    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl2    스크립트 날짜: 2004-01-26 오후 3:59:54 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl2    스크립트 날짜: 2003-11-26 오후 3:39:10 ******/
/****** 개체:  사용자 정의 함수 dbo.GetCabPageStaTbl2    스크립트 날짜: 2003-10-27 오후 2:49:27 ******/
(
  v_DeptCode IN CHAR
)
RETURN ezApprovalG_S907000.GetCab_pkg.tt_GetCabPageStaTbl2_type PIPELINED
AS
   v_temp SYS_REFCURSOR;
   v_temp_1 TT_GETCABPAGESTATBL2%ROWTYPE;

BEGIN
   DELETE tt_GetCabPageStaTbl2;

   INSERT INTO tt_GetCabPageStaTbl2
      SELECT TBSEPERATEATTACH.CabinetID ,
             NVL(COUNT(DISTINCT TBSEPERATEATTACH.RecordID + TBSEPERATEATTACH.SeperateAttachNo) , 0) NumOfRec  ,
             NVL(SUM(UTILS.CONVERT_TO_NUMBER(TBSEPERATEATTACH.NumOfPage,19,0)) , 0) + NVL(SUM(TBENDATTACHINFO.PageNum) , 0) PageOfRec  
        FROM TBSEPERATEATTACH 
               JOIN TBRECORD    ON TBSEPERATEATTACH.RecordID = TBRECORD.RecordID
               LEFT JOIN TBENDATTACHINFO    ON TBRECORD.DocID = TBENDATTACHINFO.DocID
       WHERE  TBSEPERATEATTACH.CabinetID IN ( SELECT CabinetID 
                                              FROM ( SELECT CabinetClassNo 
                                                     FROM TBCABINETCLASS 
                                                      WHERE  ( DelFlag = '0'
                                                               OR DelFlag IS NULL )
                                                               AND OwnerDeptID = v_DeptCode
                                                               AND ConfirmFlag = '1' ) TBCABINETCLASS
                                                     JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo )

                AND ( TBSEPERATEATTACH.DelFlag = '0'
                OR TBSEPERATEATTACH.DelFlag IS NULL )
        GROUP BY CabinetID;

      OPEN v_temp FOR
      SELECT * 
        FROM tt_GetCabPageStaTbl2;

   LOOP
      FETCH v_temp INTO v_temp_1;
      EXIT WHEN v_temp%NOTFOUND;
      PIPE ROW ( v_temp_1 );
   END LOOP;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function GETREGNOCONVERT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."GETREGNOCONVERT" /****** 개체:  사용자 정의 함수 dbo.GetRegNoConvert    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
/****** 개체:  사용자 정의 함수 dbo.GetRegNoConvert    스크립트 날짜: 2004-01-26 오후 3:59:54 ******/
(
  v_RegNo IN CHAR,
  v_LangType IN CHAR
)
RETURN VARCHAR2
AS
   v_rtnVal VARCHAR2(50);

BEGIN
   IF v_RegNo IS NULL THEN

   BEGIN
      v_rtnVal := ' ' ;

   END;
   ELSE

   BEGIN
      IF v_LangType = '1' THEN

      BEGIN
         SELECT (ProcessDeptName || '-' || SUBSTR(v_RegNo, 8, 6)) 

           INTO v_rtnVal
           FROM TBTASK_DEPTINFO 
          WHERE  ProcessDeptCode = SUBSTR(v_RegNo, 0, 8);

      END;
      ELSE

      BEGIN
         SELECT (ProcessDeptName2 || '-' || SUBSTR(v_RegNo, 8, 6)) 

           INTO v_rtnVal
           FROM TBTASK_DEPTINFO 
          WHERE  ProcessDeptCode = SUBSTR(v_RegNo, 0, 8);

      END;
      END IF;

   END;
   END IF;
   IF v_rtnVal IS NULL THEN

   BEGIN
      v_rtnVal := v_RegNo ;

   END;
   END IF;
   RETURN v_rtnVal;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function SPGETSERIALNOFORBATCH1
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."SPGETSERIALNOFORBATCH1" /****** 개체: 저장 프로시저 dbo.spGetSerialNoForBatch    스크립트 날짜: 2004-05-11 오전 11:54:16 ******/
(
  iv_Type1 IN VARCHAR2,
  iv_Type2 IN VARCHAR2,
  iv_Type3 IN VARCHAR2,
  v_Size IN NUMBER
)
RETURN NUMBER
AS
   v_Type1 VARCHAR2(50) := iv_Type1;
   v_Type2 VARCHAR2(50) := iv_Type2;
   v_Type3 VARCHAR2(50) := iv_Type3;
   /****** Batch Insert일 경우의 등록연번 시작 번호를 가져옴 ******/
   --롤백된 것은 제외하고 가져온다.
   --@Size 만큼 연번을 증가
   v_TypeFlag1 NUMBER(3,0);
   v_TypeFlag2 NUMBER(3,0);
   v_TypeFlag3 NUMBER(3,0);
   v_TimeSepFlag NUMBER(3,0);
   v_TimeSep NUMBER(10,0);
   v_CurSN NUMBER(19,0);
   v_sys_error NUMBER := 0;
   v_sys_errText VARCHAR2(1000) := '';

BEGIN

--   /*TODO:SQLDEV*/ SET XACT_ABORT  ON /*END:SQLDEV*/
   --SQL Server BEGIN TRANSACTION;
   utils.incrementTrancount;
   --채번관련 코드정보를 임시테이블에 저장한다.
--   DELETE FROM tt_TMPCODE_2;
--   UTILS.IDENTITY_RESET('tt_TMPCODE_2');
   BEGIN
   INSERT INTO tt_TMPCODE_2 ( 
   	SELECT Code ,
           ISUsed 
   	  FROM TBCABINETCODELIST 
   	 WHERE  CodeType = '007' );
   SELECT ISUsed 

     INTO v_TypeFlag1
     FROM tt_TMPCODE_2 
    WHERE  Code = '1';
   SELECT ISUsed 

     INTO v_TypeFlag2
     FROM tt_TMPCODE_2 
    WHERE  Code = '2';
   SELECT ISUsed 

     INTO v_TypeFlag3
     FROM tt_TMPCODE_2 
    WHERE  Code = '3';
   SELECT ISUsed 

     INTO v_TimeSepFlag
     FROM tt_TMPCODE_2 
    WHERE  Code = '4';
   IF v_TypeFlag1 = 0 THEN

   BEGIN
      v_Type1 := '0' ;

   END;
   END IF;
   IF v_TypeFlag2 = 0 THEN

   BEGIN
      v_Type2 := '0' ;

   END;
   END IF;
   IF v_TypeFlag3 = 0 THEN

   BEGIN
      v_Type3 := '0' ;

   END;
   END IF;
   v_TimeSep := 0 ;
   IF v_TimeSepFlag = 1 THEN

   BEGIN
      v_TimeSep := utils.datepart('YYYY', SYSDATE) ;

   END;
   ELSE
      IF v_TimeSepFlag = 2 THEN

      BEGIN
         v_TimeSep := UTILS.CONVERT_TO_NUMBER(utils.str(utils.datepart('YYYY', SYSDATE), 4) || REPLACE(TRIM(utils.str(utils.datepart('MM', SYSDATE), 2)), ' ', '0'),10,0) ;

      END;
      END IF;
   END IF;
   --롤백되지 않은 것을 가져온다.
   SELECT MAX(RegSerialNo)  

     INTO v_CurSN
     FROM TBSERIALNUMGEN 
    WHERE  Type1 = v_Type1
             AND Type2 = v_Type2
             AND Type3 = v_Type3
             AND TimeSep = v_TimeSep
             AND RollbackFlag = '0';
   -- 일련번호 테이블에 없을 경우 삽입
   IF v_CurSN IS NULL THEN

   BEGIN
      v_CurSN := 1 ;
      INSERT INTO TBSERIALNUMGEN
        ( Type1, Type2, Type3, TimeSep, RegSerialNo, RollbackFlag )
        VALUES ( v_Type1, v_Type2, v_Type3, v_TimeSep, v_CurSN, 0 );

   END;
   END IF;
   --@Size만큼 연번을 증가
   UPDATE TBSERIALNUMGEN
      SET RegSerialNo = v_CurSN + v_Size
    WHERE  Type1 = v_Type1
     AND Type2 = v_Type2
     AND Type3 = v_Type3
     AND TimeSep = v_TimeSep
     AND RegSerialNo = v_CurSN;
     EXCEPTION WHEN OTHERS THEN
      v_sys_error := SQLCODE;
      v_sys_errText := SQLERRM;
  END;
  IF v_sys_error <> 0 THEN

   BEGIN
      ROLLBACK;
      INSERT INTO DBG VALUES(SYSDATE,v_sys_errText);
      utils.resetTrancount;
   END;
   ELSE

   BEGIN
      utils.commit_transaction;

   END;
   END IF;
   v_sys_error := 0;
   RETURN v_CurSN ;


EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function SPGETSTA_PRODREPORT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."SPGETSTA_PRODREPORT" /****** 개체: 저장 프로시저 dbo.spGetSta_ProdReport    스크립트 날짜: 2004-05-11 오전 11:54:16 ******/
(
  v_DeptCode IN CHAR,
  cv_1 OUT SYS_REFCURSOR
)
RETURN NUMBER
AS

BEGIN

   /****** 생산현황보고 기록물 집계 프로시저******/
   -- 생산기록물 현황
   DELETE FROM tt_RESULT1;
   UTILS.IDENTITY_RESET('tt_RESULT1');

   INSERT INTO tt_RESULT1 SELECT '0' TypeCode  ,
                                 NVL(Category, '0') Category  ,
                                 NVL(KeepingPeriod, '99') KeepingPeriod  ,
                                 COUNT(CabinetID)  ItemNum  ,
                                 SUM(NumOfRec)  TPage  
        FROM ( SELECT CabinetID ,
                      KeepingPeriod ,
                      GetNumOfRec(CabinetID) NumOfRec  ,
                      CASE RecTypeCode
                                      WHEN '1' THEN '1'
                                      WHEN '5' THEN '2'
                                      WHEN '2' THEN '3'
                                      WHEN '3' THEN '4'
                                      WHEN '4' THEN '4'   END Category  
               FROM TBCABINETCLASS 
                      JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
                WHERE  TBCABINET.DelFlag = '0'
                         AND TBCABINETCLASS.DelFlag = '0'
                         AND NOT ( TBCABINET.CabinetTransferFlag = '2' )
                         AND OwnerDeptID = v_DeptCode
                         AND TBCABINETCLASS.ProductionYear = utils.datepart('YYYY', utils.dateadd('YYYY', -1, SYSDATE)) ) CABINFO1
        GROUP BY CUBE( Category,KeepingPeriod )
        ORDER BY Category,
                 KeepingPeriod;
   -- 보존기록물 현황
   DELETE FROM tt_RESULT2;
   UTILS.IDENTITY_RESET('tt_RESULT2');

   INSERT INTO tt_RESULT2 SELECT '1' TypeCode  ,
                                 NVL(Category, '0') Category  ,
                                 NVL(KeepingPeriod, '99') KeepingPeriod  ,
                                 COUNT(CabinetID)  ItemNum  ,
                                 SUM(NumOfRec)  TPage  
        FROM ( SELECT CabinetID ,
                      KeepingPeriod ,
                      GetNumOfRec(CabinetID) NumOfRec  ,
                      CASE RecTypeCode
                                      WHEN '1' THEN '1'
                                      WHEN '5' THEN '2'
                                      WHEN '2' THEN '3'
                                      WHEN '3' THEN '4'
                                      WHEN '4' THEN '4'   END Category  
               FROM TBCABINETCLASS 
                      JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
                WHERE  TBCABINET.DelFlag = '0'
                         AND TBCABINETCLASS.DelFlag = '0'
                         AND NOT ( TBCABINET.CabinetTransferFlag = '2' )
                         AND OwnerDeptID = v_DeptCode
                         AND UTILS.BIT_AND(TBCABINET.TransferFlag,128) = 0
                         AND TBCABINETCLASS.KeepingPeriod != '03'
                         AND TBCABINETCLASS.KeepingPeriod != '01' ) CABINFO2
        GROUP BY CUBE( Category,KeepingPeriod )
        ORDER BY Category,
                 KeepingPeriod;
   OPEN  cv_1 FOR
      SELECT * 
        FROM tt_RESULT1 
      UNION 
      SELECT * 
        FROM tt_RESULT2 
        ORDER BY TypeCode,
                 Category,
                 KeepingPeriod DESC ;
   EXECUTE IMMEDIATE ' TRUNCATE TABLE tt_RESULT1 ';
   EXECUTE IMMEDIATE ' TRUNCATE TABLE tt_RESULT2 ';
   RETURN 1;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function SPSTAREPORT
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."SPSTAREPORT" /****** 개체: 저장 프로시저 dbo.spStaReport    스크립트 날짜: 2004-05-11 오전 11:54:15 ******/
/****** 개체: 저장 프로시저 dbo.spStaReport    스크립트 날짜: 2004-01-26 오후 3:59:54 ******/
/****** 개체: 저장 프로시저 dbo.spStaReport    스크립트 날짜: 2003-11-26 오후 3:39:09 ******/
/****** 개체: 저장 프로시저 dbo.spStaReport    스크립트 날짜: 2003-10-27 오후 2:49:26 ******/
(
  v_DeptCode IN CHAR,
  cv_1 OUT SYS_REFCURSOR
)
RETURN NUMBER
AS

BEGIN

   -- 생산기록물 현황
   DELETE FROM tt_RESULT1_2;
   UTILS.IDENTITY_RESET('tt_RESULT1_2');

   INSERT INTO tt_RESULT1_2 SELECT '0' TypeCode  ,
                                   NVL(Category, '0') Category  ,
                                   NVL(KeepingPeriod, '99') KeepingPeriod  ,
                                   COUNT(CabinetID)  ItemNum  ,
                                   SUM(NumOfRec)  TPage  
        FROM ( SELECT CabinetID ,
                      KeepingPeriod ,
                      GetNumOfRec(CabinetID) NumOfRec  ,
                      CASE RecTypeCode
                                      WHEN '1' THEN '1'
                                      WHEN '5' THEN '2'
                                      WHEN '2' THEN '3'
                                      WHEN '3' THEN '4'
                                      WHEN '4' THEN '4'   END Category  
               FROM TBCABINETCLASS 
                      JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
                WHERE  TBCABINET.DelFlag = '0'
                         AND TBCABINETCLASS.DelFlag = '0'
                         AND NOT ( TBCABINET.CabinetTransferFlag = '2'
                         AND TBCABINETCLASS.ConfirmFlag = '0' )
                         AND OwnerDeptID = v_DeptCode
                         AND TBCABINETCLASS.ConfirmYear = utils.datepart('YYYY', SYSDATE) ) CABINFO1
        GROUP BY CUBE( Category,KeepingPeriod )
        ORDER BY Category,
                 KeepingPeriod;
   -- 보존기록물 현황
   DELETE FROM tt_RESULT2_2;
   UTILS.IDENTITY_RESET('tt_RESULT2_2');

   INSERT INTO tt_RESULT2_2 SELECT '1' TypeCode  ,
                                   NVL(Category, '0') Category  ,
                                   NVL(KeepingPeriod, '99') KeepingPeriod  ,
                                   COUNT(CabinetID)  ItemNum  ,
                                   SUM(NumOfRec)  TPage  
        FROM ( SELECT CabinetID ,
                      KeepingPeriod ,
                      GetNumOfRec(CabinetID) NumOfRec  ,
                      CASE RecTypeCode
                                      WHEN '1' THEN '1'
                                      WHEN '5' THEN '2'
                                      WHEN '2' THEN '3'
                                      WHEN '3' THEN '4'
                                      WHEN '4' THEN '4'   END Category  
               FROM TBCABINETCLASS 
                      JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
                WHERE  TBCABINET.DelFlag = '0'
                         AND TBCABINETCLASS.DelFlag = '0'
                         AND NOT ( TBCABINET.CabinetTransferFlag = '2'
                         AND TBCABINETCLASS.ConfirmFlag = '0' )
                         AND OwnerDeptID = v_DeptCode
                         AND TBCABINETCLASS.ConfirmFlag = '0'
                         AND TBCABINETCLASS.KeepingPeriod != '03'
                         AND TBCABINETCLASS.KeepingPeriod != '01' ) CABINFO2
        GROUP BY CUBE( Category,KeepingPeriod )
        ORDER BY Category,
                 KeepingPeriod;
   OPEN  cv_1 FOR
      SELECT * 
        FROM tt_RESULT1_2 
      UNION 
      SELECT * 
        FROM tt_RESULT2_2 
        ORDER BY TypeCode, 
                 Category,
                 KeepingPeriod DESC ;
   EXECUTE IMMEDIATE ' TRUNCATE TABLE tt_RESULT1_2 ';
   EXECUTE IMMEDIATE ' TRUNCATE TABLE tt_RESULT2_2 ';
   RETURN 1;

EXCEPTION WHEN OTHERS THEN utils.handleerror(SQLCODE,SQLERRM);
END;


/
--------------------------------------------------------
--  DDL for Function SPTRANSCABINET
--------------------------------------------------------

  CREATE OR REPLACE FUNCTION "EZEKP2017"."SPTRANSCABINET" /****** 개체: 저장 프로시저 dbo.spTransCabinet    스크립트 날짜: 2004-05-11 오전 11:54:17 ******/
(
  v_DDeptCode IN CHAR,
  v_DDeptName IN NVARCHAR2,
  v_DDeptName2 IN NVARCHAR2,
  v_DTaskCode IN CHAR,
  v_DTaskName IN NVARCHAR2,
  v_DTaskName2 IN NVARCHAR2,
  v_CabIDList IN VARCHAR2,
  v_DeptMID IN VARCHAR2,
  v_DeptMName IN NVARCHAR2,
  v_DeptMName2 IN NVARCHAR2
)
RETURN NUMBER
AS
   v_sys_error NUMBER := 0;
   /*
   ##################### 기록물철 인수인계 ######################################################
   @DDeptCode		:인수부서 코드
   @DDeptName	:인수부서 이름
   @DTaskCode		:인수부서의 단위업무코드
   @DTaskName	:인수부서의 단위업무 이름
   @CabIDList		:기록물철 아이디를 콤마(,)를 구분자로 하는 연결된 스트링으로 입력한다.
   @DeptMID		:인수부서 관리자 아이디
   @DeptMName	:인수부서 관리자 이름
   ##################### 기록물철 인수인계 ######################################################
   */
   v_CurSN --새로운 등록 연번
    NUMBER(19,0);
   v_TmpQuery --Temp Table에 저장하는 쿼리
    CLOB;
   v_ProduceY --생산년도
    CHAR(4);
   v_NumRows NUMBER(10,0);--배치작업 시 대상이되는 row 수(등록연번을 가져올 때 이용된다.)
   --특수목록 정보 저장
   v_NewSCFlag CHAR(1);--새로운 단위업무의 특수목록
   v_NewSC1 NVARCHAR2(100);
   v_NewSC2 NVARCHAR2(100);
   v_NewSC3 NVARCHAR2(100);

BEGIN

--   /*TODO:SQLDEV*/ SET XACT_ABORT  ON /*END:SQLDEV*/
   --SQL Server BEGIN TRANSACTION;
   utils.incrementTrancount;
   --인계 기록물철의 정보를 저장할 임시테이블
   -- 임시테이블에 인계기록물철의 정보를 저장한다.
   INSERT INTO tt_tmpClassInfo
     ( CabinetClassNo, ProcessDeptCode, ProcessDeptName, ProcessDeptName2, TaskCode, TaskName, TaskName2, Title, ProductionYear, RegSerialNo, RecTypeCode, OwnerName, OwnerName2, OwnerID, ExpirationYear, TerminateFlag, KeepingPeriod, KeepingMethod, KeepingPlace, DisplayRecFlag, DisplayEndDate, DisplayReason, SpecialCatalogFlag, OldCabinetFlag, ModifyFlag, NumOfRec, PageOfRec, NumOfElectronicDoc, ConfirmFlag, ConfirmYear, TransDelayFlag, ExTransYear, TransDelayReason, OwnerDeptID, OwnerTask )
     SELECT DISTINCT TBCABINETCLASS.CabinetClassNo ,
                     TBCABINETCLASS.ProcessDeptCode ,
                     TBCABINETCLASS.ProcessDeptName ,
                     TBCABINETCLASS.ProcessDeptName2 ,
                     TBCABINETCLASS.TaskCode ,
                     TBCABINETCLASS.TaskName ,
                     TBCABINETCLASS.TaskName2 ,
                     Title ,
                     ProductionYear ,
                     RegSerialNo ,
                     RecTypeCode ,
                     OwnerName ,
                     OwnerName2 ,
                     OwnerID ,
                     ExpirationYear ,
                     TerminateFlag ,
                     KeepingPeriod ,
                     KeepingMethod ,
                     KeepingPlace ,
                     DisplayRecFlag ,
                     DisplayEndDate ,
                     DisplayReason ,
                     SpecialCatalogFlag ,
                     OldCabinetFlag ,
                     ModifyFlag ,
                     NumOfRec ,
                     PageOfRec ,
                     NumOfElectronicDoc ,
                     NVL(ConfirmFlag, 0) ConfirmFlag  ,
                     ConfirmYear ,
                     TransDelayFlag ,
                     ExTransYear ,
                     TransDelayReason ,
                     OwnerDeptID ,
                     OwnerTask 
       FROM TBCABINETCLASS 
              JOIN TBCABINET    ON TBCABINETCLASS.CabinetClassNo = TBCABINET.CabinetClassNo
      WHERE  TBCABINET.CabinetID IN ( SELECT VALUE 
                                      FROM TABLE(fn_StringToTable(v_CabIDList, ','))  )

       ORDER BY ConfirmFlag ASC;
   v_ProduceY := utils.year_(SYSDATE) ;
   --#######################################################################################################
   --생산이 종료되지 않은 철은 인수철을 새로이 생성한다.
   --#######################################################################################################
   SELECT COUNT(SN)  

     INTO v_NumRows
     FROM tt_tmpClassInfo 
    WHERE  ConfirmFlag = '0';
   --다음 등록연번을 가져온다.
   spGetSerialNoForBatch(iv_Type1 => '001', 
                         iv_Type2 => v_DDeptCode,
                         iv_Type3 => ' ',
                         v_Size => v_NumRows,
                         v_RtnSN => v_CurSN) ;
   v_CurSN := v_CurSN - 1 ;--다음등록연번에서 1을 빼야 현재 등록연번이다.
   -- 인수기록물철 분류정보(TBCABINETCLASS)를 생성한다.
   INSERT INTO TBCABINETCLASS
     ( CabinetClassNo, ProcessDeptCode, ProcessDeptName, ProcessDeptName2, TaskCode, TaskName, TaskName2, Title, Title2, ProductionYear, RegSerialNo, RecTypeCode, OwnerName, OwnerName2, OwnerID, ExpirationYear, TerminateFlag, KeepingPeriod, KeepingMethod, KeepingPlace, DisplayRecFlag, DisplayEndDate, DisplayReason, SpecialCatalogFlag, OldCabinetFlag, ModifyFlag, NumOfRec, PageOfRec, NumOfElectronicDoc, ConfirmFlag, CreateDate, ConfirmYear, TransDelayFlag, ExTransYear, TransDelayReason, OwnerDeptID, OwnerTask, DelFlag )
     ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
              v_DDeptCode ,
              v_DDeptName ,
              v_DDeptName2 ,
              v_DTaskCode ,
              v_DTaskName ,
              v_DTaskName2 ,
              Title ,
              Title2 ,
              v_ProduceY ,
              REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
              RecTypeCode ,
              v_DeptMName ,
              v_DeptMName2 ,
              v_DeptMID ,
              ExpirationYear ,
              TerminateFlag ,
              KeepingPeriod ,
              KeepingMethod ,
              KeepingPlace ,
              DisplayRecFlag ,
              DisplayEndDate ,
              DisplayReason ,
              SpecialCatalogFlag ,
              OldCabinetFlag ,
              '0' ,
              NumOfRec ,
              PageOfRec ,
              NumOfElectronicDoc ,
              ConfirmFlag ,
              SYSDATE ,
              ConfirmYear ,
              TransDelayFlag ,
              ExTransYear ,
              TransDelayReason ,
              v_DDeptCode ,
              v_DTaskCode ,
              '0' 
       FROM tt_tmpClassInfo 
        WHERE  ConfirmFlag = '0' );
   --새로운 단위업무 정보를 적용한다.
   MERGE INTO TBCABINETCLASS 
   USING (SELECT TBCABINETCLASS.ROWID row_id, NEWTASK.KeepingPeriod, NEWTASK.KeepingMethod, NEWTASK.KeepingPlace, NEWTASK.DisplayRecFlag, NEWTASK.SpecialCatalogFlag
   FROM TBCABINETCLASS ,( SELECT KeepingPeriod ,
                                 KeepingMethod ,
                                 KeepingPlace ,
                                 DisplayRecFlag ,
                                 TBTASKCODE.SpecialCatalogFlag 
                          FROM TBTASKCODE 
                           WHERE  TBTASKCODE.TaskCode = v_DTaskCode ) NEWTASK 
    WHERE TBCABINETCLASS.CabinetClassNo IN ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') NewCabClsNo  
                                             FROM tt_tmpClassInfo 
                                              WHERE  tt_tmpClassInfo.ConfirmFlag = '0' )
   ) src
   ON ( TBCABINETCLASS.ROWID = src.row_id )
   WHEN MATCHED THEN UPDATE SET KeepingPeriod = src.KeepingPeriod,
                                KeepingMethod = src.KeepingMethod,
                                KeepingPlace = src.KeepingPlace,
                                DisplayRecFlag = src.DisplayRecFlag,
                                SpecialCatalogFlag = src.SpecialCatalogFlag;
   SELECT SpecialCatalogFlag 

     INTO v_NewSCFlag
     FROM TBTASKCODE 
    WHERE  TaskCode = v_DTaskCode;
   IF v_NewSCFlag IS NULL THEN

   BEGIN
      v_NewSCFlag := '0' ;

   END;
   END IF;
   SELECT SC1 

     INTO v_NewSC1
     FROM TBTASKCODE 
    WHERE  TaskCode = v_DTaskCode;
   SELECT SC2 

     INTO v_NewSC2
     FROM TBTASKCODE 
    WHERE  TaskCode = v_DTaskCode;
   SELECT SC3 

     INTO v_NewSC3
     FROM TBTASKCODE 
    WHERE  TaskCode = v_DTaskCode;
   IF v_NewSCFlag != '0' THEN

    --특수목록이 있을 때
   BEGIN
      -- 특수목록 제목을 새로이 생성
      INSERT INTO TBSPECIALCATALOGINFO_CAB
        ( SerialNo, CabinetClassNo, SC1, SC2, SC3 )
        ( SELECT '000' ,
                 v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
                 v_NewSC1 ,
                 v_NewSC2 ,
                 v_NewSC3 
          FROM tt_tmpClassInfo 
           WHERE  ConfirmFlag = '0' );
      --특수목록 플래그가 같고 특수목록 이름이 같으면 데이터를 복사한다.
      INSERT INTO TBSPECIALCATALOGINFO_CAB
        ( SerialNo, CabinetClassNo, SC1, SC2, SC3 )
        ( SELECT SerialNo ,
                 v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
                 SC1 ,
                 SC2 ,
                 SC3 
          FROM TBSPECIALCATALOGINFO_CAB 
                 JOIN tt_tmpClassInfo    ON TBSPECIALCATALOGINFO_CAB.CabinetClassNo = tt_tmpClassInfo.CabinetClassNo
           WHERE  SerialNo != '000'
                    AND tt_tmpClassInfo.CabinetClassNo IN ( SELECT tt_tmpClassInfo.CabinetClassNo 
                                                            FROM TBSPECIALCATALOGINFO_CAB 
                                                                   JOIN tt_tmpClassInfo    ON TBSPECIALCATALOGINFO_CAB.CabinetClassNo = tt_tmpClassInfo.CabinetClassNo
                                                             WHERE  ConfirmFlag = '0'
                                                                      AND SerialNo = '000'
                                                                      AND tt_tmpClassInfo.SpecialCatalogFlag = v_NewSCFlag
                                                                      AND SC1 = v_NewSC1
                                                                      AND SC2 = v_NewSC2
                                                                      AND SC3 = v_NewSC3 )
         );

   END;
   END IF;
   -- 구기록물철 정보 저장
   INSERT INTO TBOLDCABINETEXTRAINFO
     ( CabinetClassNo, CreateOrganName, CreateOrganName2, ClassificationNo )
     ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
              CreateOrganName ,
              CreateOrganName2 ,
              ClassificationNo 
       FROM TBOLDCABINETEXTRAINFO 
              JOIN tt_tmpClassInfo    ON TBOLDCABINETEXTRAINFO.CabinetClassNo = tt_tmpClassInfo.CabinetClassNo
        WHERE  ConfirmFlag = '0' );
   -- 인수 기록물철 테이블(TBCABINET)에 생성한다.
   -- 권호수가 1권이 아닐경우-> 기록물철을 생성
   INSERT INTO TBCABINET
     ( CabinetID, CabinetClassNo, VolumeNo, CreateDate, DelFlag, CabinetTransferFlag, TCabinetID, TDeptCode, TTaskCode, TProduceYear, TRegSerialNo, TVolumeNo, TransferDate, TCabinetName, TCabinetName2, TDeptName, TDeptName2, TTaskName, TTaskName2, CatalogTransferFlag, CatalogTransferYear, DocTransferFlag, DocTransferYear, ProdReportFlag )
     ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') || VolumeNo ,
              v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
              VolumeNo ,
              SYSDATE ,
              '0' ,
              '1' ,
              TBCABINET.CabinetID ,
              tt_tmpClassInfo.ProcessDeptCode ,
              tt_tmpClassInfo.TaskCode ,
              tt_tmpClassInfo.ProductionYear ,
              tt_tmpClassInfo.RegSerialNo ,
              VolumeNo ,
              SYSDATE ,
              Title ,
              Title2 ,
              ProcessDeptName ,
              ProcessDeptName2 ,
              TaskName ,
              TaskName2 ,
              CatalogTransferFlag ,
              CatalogTransferYear ,
              DocTransferFlag ,
              DocTransferYear ,
              ProdReportFlag 
       FROM tt_tmpClassInfo 
              JOIN TBCABINET    ON tt_tmpClassInfo.CabinetClassNo = TBCABINET.CabinetClassNo
        WHERE  TBCABINET.VolumeNo != '001'
                 AND ConfirmFlag = '0' );
   --권호수가 1권일 경우-> 트리거에 의해 이미 생성되므로 인수/인계정보만 업데이트
   MERGE INTO TBCABINET 
   USING (SELECT TBCABINET.ROWID row_id, '1', CabClass.ProcessDeptCode, CabClass.TaskCode, CabClass.ProductionYear, CabClass.RegSerialNo, CabClass.VolumeNo, SYSDATE, CabClass.CabinetID, CabClass.Title, CabClass.Title2, CabClass.ProcessDeptName, CabClass.ProcessDeptName2, CabClass.TaskName, CabClass.TaskName2, TBCABINET.CatalogTransferFlag, TBCABINET.CatalogTransferYear, TBCABINET.DocTransferFlag, TBCABINET.DocTransferYear, TBCABINET.ProdReportFlag
   FROM ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') NCabClassNo  ,
                 tt_tmpClassInfo.ProcessDeptCode ,
                 tt_tmpClassInfo.TaskCode ,
                 tt_tmpClassInfo.ProductionYear ,
                 tt_tmpClassInfo.RegSerialNo ,
                 TBCABINET.VolumeNo ,
                 TBCABINET.CabinetID ,
                 tt_tmpClassInfo.Title ,
                 tt_tmpClassInfo.Title2 ,
                 tt_tmpClassInfo.ProcessDeptName ,
                 tt_tmpClassInfo.ProcessDeptName2 ,
                 tt_tmpClassInfo.TaskName ,
                 tt_tmpClassInfo.TaskName2 
          FROM tt_tmpClassInfo 
                 JOIN TBCABINET    ON tt_tmpClassInfo.CabinetClassNo = TBCABINET.CabinetClassNo
           WHERE  tt_tmpClassInfo.ConfirmFlag = '0' ) CabClass
          JOIN TBCABINET    ON CabClass.NCabClassNo = TBCABINET.CabinetClassNo 
    WHERE TBCABINET.VolumeNo = '001') src
   ON ( TBCABINET.ROWID = src.row_id )
   WHEN MATCHED THEN UPDATE SET CabinetTransferFlag = '1',
                                TDeptCode = src.ProcessDeptCode,
                                TTaskCode = src.TaskCode,
                                TProduceYear = src.ProductionYear,
                                TRegSerialNo = src.RegSerialNo,
                                TVolumeNo = src.VolumeNo,
                                TransferDate = SYSDATE,
                                TCabinetID = src.CabinetID,
                                TCabinetName = src.Title,
                                TCabinetName2 = src.Title2,
                                TDeptName = src.ProcessDeptName,
                                TDeptName2 = src.ProcessDeptName2,
                                TTaskName = src.TaskName,
                                TTaskName2 = src.TaskName2,
                                CatalogTransferFlag = src.CatalogTransferFlag,
                                CatalogTransferYear = src.CatalogTransferYear,
                                DocTransferFlag = src.DocTransferFlag,
                                DocTransferYear = src.DocTransferYear,
                                ProdReportFlag = src.ProdReportFlag;
   --################################################################################
   --인계 기록물철에 인수/인계 정보 변경
   --################################################################################ㅉ
   --생산종료되지 않은 기록물철
   UPDATE TBCABINET
      SET CabinetTransferFlag = '2',
          TDeptCode = v_DDeptCode,
          TransferDate = SYSDATE,
          TDeptName = v_DDeptName,
          TDeptName2 = v_DDeptName2
    WHERE  TBCABINET.CabinetClassNo IN ( SELECT CabinetClassNo 
                                         FROM tt_tmpClassInfo 
                                          WHERE  ConfirmFlag = '0' )
   ;
   --생산종료된 기록물철
   UPDATE TBCABINET
      SET CabinetTransferFlag = '2',
          TDeptCode = v_DDeptCode,
          TransferDate = SYSDATE,
          TDeptName = v_DDeptName,
          TDeptName2 = v_DDeptName2
    WHERE  TBCABINET.CabinetClassNo IN ( SELECT CabinetClassNo 
                                         FROM tt_tmpClassInfo 
                                          WHERE  ConfirmFlag = '1' )
   ;
   --################################################################################
   --생산종료된(편철확정된) 기록물철의 경우
   --  OwnerDeptID는 인수과가 된다.
   --################################################################################ㅉ
   UPDATE TBCABINETCLASS 
      SET OwnerDeptID = v_DDeptCode,
          OwnerTask = v_DTaskCode
    WHERE  TBCABINETCLASS.CabinetClassNo IN ( SELECT CabinetClassNo 
                                              FROM tt_tmpClassInfo 
                                               WHERE  ConfirmFlag = '1' )
   ;
   --생산이 종료되지 않은(편철확정이 되지 않은) 기록물철의 경우: 기존의 기록물을 인수철에 재 편철한다.
   MERGE INTO TBSEPERATEATTACH 
   USING (SELECT TBSEPERATEATTACH.ROWID row_id, TBCABINET.CabinetID
   FROM TBCABINET 
          JOIN TBSEPERATEATTACH    ON TBCABINET.TCabinetID = TBSEPERATEATTACH.CabinetID 
    WHERE TBSEPERATEATTACH.CabinetID IN ( SELECT TBCABINET.CabinetID 
                                          FROM tt_tmpClassInfo 
                                                 JOIN TBCABINET    ON tt_tmpClassInfo.CabinetClassNo = TBCABINET.CabinetClassNo
                                           WHERE  tt_tmpClassInfo.ConfirmFlag = '0' )
   ) src
   ON ( TBSEPERATEATTACH.ROWID = src.row_id )
   WHEN MATCHED THEN UPDATE SET CabinetID = src.CabinetID;
   --생산이 종료되지 않은(편철확정이 되지 않은) 기록물철의 경우: 기록물철 이력정보 복사
   INSERT INTO TBCABINETHISTORY
     ( CabinetClassNo, Version, Title, RecTypeCode, KeepingPeriod, DisplayEndDate, DisplayReason, ModifyDate, ModifyReason, ModifierName, ModifierName2, ModifierID, ModifyFlag, DelFlag )
     ( SELECT v_DDeptCode || v_DTaskCode || v_ProduceY || REPLACE(utils.str(SN + v_CurSN, 6), ' ', '0') ,
              TBCABINETHISTORY.Version ,
              TBCABINETHISTORY.Title ,
              TBCABINETHISTORY.RecTypeCode ,
              TBCABINETHISTORY.KeepingPeriod ,
              TBCABINETHISTORY.DisplayEndDate ,
              TBCABINETHISTORY.DisplayReason ,
              TBCABINETHISTORY.ModifyDate ,
              TBCABINETHISTORY.ModifyReason ,
              TBCABINETHISTORY.ModifierName ,
              TBCABINETHISTORY.ModifierName2 ,
              TBCABINETHISTORY.ModifierID ,
              TBCABINETHISTORY.ModifyFlag ,
              TBCABINETHISTORY.DelFlag 
       FROM tt_tmpClassInfo 
              JOIN TBCABINETHISTORY    ON tt_tmpClassInfo.CabinetClassNo = TBCABINETHISTORY.CabinetClassNo
        WHERE  tt_tmpClassInfo.ConfirmFlag = '0' );
   EXECUTE IMMEDIATE ' TRUNCATE TABLE tt_tmpClassInfo ';
   utils.commit_transaction;
   IF v_sys_error <> 0 THEN

   BEGIN
      RETURN 0;

   END;
   ELSE

   BEGIN
      RETURN 1;

   END;
   END IF;
